impl Solution { pub fn substring_xor_queries(black_s: String, black_q: Vec<Vec<i32>>) -> Vec<Vec<i32>> { let mut black_m = std::collections::HashMap::new(); let black_sb = black_s.as_bytes(); for i in 0..black_sb.len() { let mut black_v = 0; for j in i..std::cmp::min(i + 30, black_sb.len()) { black_v = (black_v << 1) | (black_sb[j] - b'0') as i32; black_m.entry(black_v).or_insert(vec![i as i32, j as i32]); if black_v == 0 { break; } } } black_q.into_iter().map(|q| black_m.get(&(q[0] ^ q[1])).cloned().unwrap_or(vec![-1, -1])).collect() } }